var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 9월 30일 런던, 화이트 채플","JPN":"1888年9月30日　ロンドン、ホワイトチャペル","ENG":"September 30, 1888, London, White Chapel","TWN":"1888年9月30日 倫敦，白教堂","SCN":"1888年9月30日 伦敦，白教堂","DEU":"September 30, 1888, London, White Chapel","FRA":"September 30, 1888, London, White Chapel"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PAWNSHOP_SWANSONG_NPC_NULL","text":{"KOREA":"들어오쇼.","JPN":"どうぞ。","ENG":"Come in.","TWN":"進來吧。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PAWNSHOP_SWANSONG_NPC_NULL","text":{"KOREA":"수녀님이시구먼, 여긴 어쩐 일로 오셨소?","JPN":"シスターさんかい。ここにはなんの用ですか？","ENG":"Sister? What brings you here?","TWN":"修女，你怎麼來這裡了？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"파노라마를 극장 밖에서 쓰겠다고요?","JPN":"パノラマを劇場の外で使うですって！？","ENG":"You wish to use Panorama outside of the theater?","TWN":"你說要在劇院外使用全景？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"미쳤어요? 왕실 마도구를 허가없이 반출하는 건, 중대한 범죄라고요!","JPN":"正気ですか？　王室の魔道具を許可なしで搬出するのは重罪ですよ！","ENG":"Are you mad? Taking out the royal Curio without permission is a serious crime!","TWN":"你瘋了嗎？擅自帶出王室魔法道具可是重大的犯罪行為！"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 괜찮아.","JPN":"ふふ、大丈夫だ。","ENG":"Haha, it'll be fine.","TWN":"呵呵，不會那麼嚴重的。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네의 전속 스태프, 메리 제인 양은 오늘 하루 휴가를 내지 않았나?","JPN":"君の専属スタッフ、メリー・ジェーン嬢は今日一日休みを取っているだろう。","ENG":"Hasn't your personal staff, Mary Jane, taken the entire day off today?","TWN":"你的專屬職員，瑪麗·珍今天不是請假了嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"한 개쯤, 조용히 쓰고 돌려놓으면 아무런 문제가 되지 않을 걸세.","JPN":"こっそり使って戻しておけば一つくらい大したことないさ。","ENG":"It won't be a problem if we take one out quietly and return it before anyone notices.","TWN":"拿走一個，用完再悄悄放回去，不會有任何問題的。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"무슨 그런 안일한 생각을! 이건 배우로서 커리어가 달린 문제예요!","JPN":"なんて甘い考え方…！　これは役者のキャリアに関わる問題です！","ENG":"That's so reckless! This is my career on the line!","TWN":"怎麼能有那種輕率的想法！這是關乎我演員生涯的大事啊！"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"다른 사람에게 들켰다간 그냥 끝나지 않을 거라고요!","JPN":"バレたらただじゃ済みませんから！","ENG":"If someone sees me, it won't end well!","TWN":"如果被其他人發現的話，可就完蛋了！"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"으음? 들킨다고? 그거 이상하군.","JPN":"ん？　バレる？　おかしなことを言うな。","ENG":"Mm? Sees you? That's odd.","TWN":"嗯？被發現了？那可真奇怪。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네 정도의 배우라면 어떤 상황도, 어떤 배역도 완벽히 소화할 수 있다고 생각했는데.","JPN":"君ほどの役者なら、どんな状況でも、どんな役でも完璧にやりすごせると思っていたが。","ENG":"I thought an actress of your stature could handle any role in any situation perfectly.","TWN":"我原以為像你這樣的演員，無論什麼情況，無論什麼角色都能完美駕馭。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"설령, 그게 사전에 준비된 무대 위가 아닐지라도 말이야.","JPN":"たとえそれが、事前に用意された舞台の上じゃなくてもな。","ENG":"Even if it's not on a stage prepared in advance.","TWN":"即使那不是事先準備好的舞台。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"뭐라고요……?","JPN":"なんですって……？","ENG":"What...?","TWN":"你說什麼……？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"뭐, 어쩔 수 없겠지. 자네가 도저히 못 하겠다면, 나도 다른 방법을…….","JPN":"まあ、仕方ないだろう。君がどうしても無理だというなら、他の方法を……","ENG":"Oh, well. If you can't do it, I'll have to find another way–","TWN":"不過，沒辦法了。如果你實在做不到的話，我也只能另想辦法……。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"잠깐.","JPN":"待って。","ENG":"Wait.","TWN":"等一下。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그 발언, 지금 제 실력을 의심하는 건가요?","JPN":"今の発言、私の実力を疑っているんですか？","ENG":"Are you doubting my skills right now?","TWN":"你這話，是在懷疑我的實力嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"참 무례하시네요.","JPN":"まったくもって失礼ですね。","ENG":"Rude doesn't even describe your behavior.","TWN":"真是無禮啊。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"여기서 얌전히 기다리기나 하세요.","JPN":"ここで大人しく待っていてください。","ENG":"You just wait here.","TWN":"在這裡乖乖等著吧。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"보란 듯이 정보를 얻어내서 그 경솔한 발언, 사과하게 만들어 드릴 테니까!","JPN":"見事情報を手に入れて、先程の発言を謝罪させますから！","ENG":"I'll make you eat your words and apologize to me by getting that information!","TWN":"我會拿到資訊，讓你為自己輕率的言論道歉！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이걸로 다섯 번째 가게…….","JPN":"これで五か所目……","ENG":"This should be the fifth shop...","TWN":"這是第五家店了……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};